// Geist static TTFs (OFL, vercel/geist-font v1.7.2), base64-inlined so the
// PDF route needs no filesystem/tracing setup on Vercel. Server-only;
// never import this from client code.

const GEIST_REGULAR_B64 =
  "";

const GEIST_SEMIBOLD_B64 =
  "";

const GEIST_EXTRABOLD_B64 =
  "";

export const GEIST_REGULAR: Uint8Array = Uint8Array.from(Buffer.from(GEIST_REGULAR_B64, "base64"));

export const GEIST_SEMIBOLD: Uint8Array = Uint8Array.from(Buffer.from(GEIST_SEMIBOLD_B64, "base64"));

export const GEIST_EXTRABOLD: Uint8Array = Uint8Array.from(Buffer.from(GEIST_EXTRABOLD_B64, "base64"));
